  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Die Logik der RBI — Stablecoins bestehen die "Geldtests" nicht</text>
    <g font-family="sans-serif">
      <text x="20" y="66" fill="#f87171" font-size="14" font-weight="700">Die 3 Geldeigenschaften der BIZ — Stablecoins erfüllen sie nicht</text>
      <rect x="20" y="80" width="205" height="92" rx="10" fill="#2a1416" stroke="#ef4444" stroke-width="1.6"/>
      <text x="122" y="112" fill="#fca5a5" text-anchor="middle" font-size="14" font-weight="800">Einheitlichkeit ✗</text>
