      <text x="578" y="156" fill="#e4e4e7" text-anchor="middle" font-size="13">Abwicklung</text>
      <line x1="350" y1="184" x2="350" y2="212" stroke="#52525b" stroke-width="2"/>
      <text x="20" y="240" fill="#38bdf8" font-size="14" font-weight="700">Die dreifache Mauer der RBI (Ring-Fencing)</text>
      <rect x="20" y="254" width="205" height="110" rx="10" fill="#0e2233" stroke="#38bdf8" stroke-width="1.6"/>
      <text x="122" y="290" fill="#7dd3fc" text-anchor="middle" font-size="14" font-weight="800">① Kein Zahlungsverkehr</text>
      <text x="122" y="318" fill="#e4e4e7" text-anchor="middle" font-size="13">keine Krypto im</text>
      <text x="122" y="336" fill="#e4e4e7" text-anchor="middle" font-size="13">Abwicklungsnetz</text>
      <rect x="248" y="254" width="205" height="110" rx="10" fill="#0e2233" stroke="#38bdf8" stroke-width="1.6"/>
      <text x="350" y="290" fill="#7dd3fc" text-anchor="middle" font-size="14" font-weight="800">② Banken begrenzen</text>
